1	export interface Customer {
2	  yearsWithMHPCO: number;
3	}
4	
5	export interface Item {
6	  type: string;
7	  material?: string;
8	  enchantment?: number;
9	  cursed?: boolean;
10	}
11	
12	export interface QuoteStep {
13	  op: "quote";
14	  items: Item[];
15	}
16	
17	export interface Damage {
18	  itemType: string;
19	  amount: number;
20	}
21	
22	export interface Incident {
23	  cause: string;
24	  damages: Damage[];
25	}
26	
27	export interface ClaimStep {
28	  op: "claim";
29	  policy: number;
30	  incident: Incident;
31	}
32	
33	export type Step = QuoteStep | ClaimStep;
34	
35	export interface Scenario {
36	  customer: Customer;
37	  steps: Step[];
38	}
39	
40	export interface QuoteResult {
41	  premium: number;
42	}
43	
44	export interface ClaimResult {
45	  payout: number;
46	  remainingCap: number;
47	}
48	
49	export type StepResult = QuoteResult | ClaimResult;
50	
51	export interface ScenarioOutput {
52	  results: StepResult[];
53	}
54	
55	const PROCESSING_FEE = 5;
56	const BLOCK_SIZE = 3;
57	const COMPONENT_BLOCK_PRICE = 60;
58	const CURSED_SURCHARGE_RATE = 0.5;
59	const HIGH_ENCHANTMENT_RATE = 0.3;
60	const HIGH_ENCHANTMENT_THRESHOLD = 5;
61	const FIRST_INSURANCE_RATE = 0.1;
62	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
63	  sword: 100,
64	  amulet: 60,
65	  staff: 80,
66	  potion: 40,
67	  rune: 25,
68	  moonstone: 25,
69	};
70	
71	const basePremium = (item: Item): number =>
72	  BASE_PREMIUM_BY_TYPE[item.type] ?? 0;
73	
74	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
75	
76	const groupByType = (items: Item[]): Map<string, Item[]> => {
77	  const groups = new Map<string, Item[]>();
78	  for (const item of items) {
79	    const existing = groups.get(item.type) ?? [];
80	    existing.push(item);
81	    groups.set(item.type, existing);
82	  }
83	  return groups;
84	};
85	
86	const sumBasePremiums = (items: Item[]): number =>
87	  items.reduce((sum, item) => sum + basePremium(item), 0);
88	
89	const groupTotal = (type: string, group: Item[]): number => {
90	  if (group.length === BLOCK_SIZE && COMPONENT_TYPES.has(type)) {
91	    return COMPONENT_BLOCK_PRICE;
92	  }
93	  return sumBasePremiums(group);
94	};
95	
96	const policyBase = (items: Item[]): number => {
97	  let total = 0;
98	  for (const [type, group] of groupByType(items)) {
99	    total += groupTotal(type, group);
100	  }
101	  return total;
102	};
103	
104	const cursedSurcharge = (items: Item[]): number =>
105	  items.reduce(
106	    (sum, item) =>
107	      sum + (item.cursed ? basePremium(item) * CURSED_SURCHARGE_RATE : 0),
108	    0,
109	  );
110	
111	const highEnchantmentSurcharge = (items: Item[]): number =>
112	  items.reduce(
113	    (sum, item) =>
114	      sum +
115	      ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
116	        ? basePremium(item) * HIGH_ENCHANTMENT_RATE
117	        : 0),
118	    0,
119	  );
120	
121	const quotePremium = (items: Item[]): number => {
122	  const base = policyBase(items);
123	  const surcharges =
124	    cursedSurcharge(items) +
125	    highEnchantmentSurcharge(items) +
126	    base * FIRST_INSURANCE_RATE;
127	  return Math.ceil(base + surcharges) + PROCESSING_FEE;
128	};
129	
130	export const processScenario = (scenario: Scenario): ScenarioOutput => {
131	  const step = scenario.steps[0] as QuoteStep;
132	  return { results: [{ premium: quotePremium(step.items) }] };
133	};
